import { useState, useEffect } from 'react';
import { formatPrice } from '../utils/helpers';
import styles from './DemoAccount.module.css';

const INITIAL_BALANCE = 10000; // $10,000 demo bakiye
const LEVERAGE_OPTIONS = [1, 5, 10, 20, 50, 100];

export default function DemoAccount({ prices, selectedCoin, signal }) {
  const [balance, setBalance]       = useState(INITIAL_BALANCE);
  const [positions, setPositions]   = useState([]);
  const [history, setHistory]       = useState([]);
  const [leverage, setLeverage]     = useState(10);
  const [amount, setAmount]         = useState('100');
  const [activeTab, setActiveTab]   = useState('positions');
  const [totalPnl, setTotalPnl]     = useState(0);

  const price = prices[selectedCoin?.sym] || selectedCoin?.basePrice || 0;

  // Pozisyonları güncelle (fiyat değişince PnL hesapla)
  useEffect(() => {
    if (!price || positions.length === 0) return;
    let pnl = 0;
    positions.forEach(pos => {
      const diff = pos.type === 'LONG'
        ? (price - pos.entryPrice) / pos.entryPrice
        : (pos.entryPrice - price) / pos.entryPrice;
      pnl += pos.margin * pos.leverage * diff;
    });
    setTotalPnl(parseFloat(pnl.toFixed(2)));
  }, [price, positions]);

  // Pozisyon aç
  const openPosition = (type) => {
    const margin = parseFloat(amount);
    if (!margin || margin <= 0 || margin > balance) return;
    if (!price) return;

    const newPos = {
      id:         Date.now(),
      sym:        selectedCoin.sym,
      type,
      entryPrice: price,
      margin,
      leverage,
      size:       margin * leverage,
      openTime:   new Date().toLocaleTimeString('tr-TR'),
      liquidPrice: type === 'LONG'
        ? price * (1 - 1 / leverage * 0.9)
        : price * (1 + 1 / leverage * 0.9),
    };

    setBalance(prev => parseFloat((prev - margin).toFixed(2)));
    setPositions(prev => [...prev, newPos]);
  };

  // Pozisyon kapat
  const closePosition = (pos) => {
    if (!price) return;
    const diff = pos.type === 'LONG'
      ? (price - pos.entryPrice) / pos.entryPrice
      : (pos.entryPrice - price) / pos.entryPrice;
    const pnl     = parseFloat((pos.margin * pos.leverage * diff).toFixed(2));
    const returned = parseFloat((pos.margin + pnl).toFixed(2));

    setBalance(prev => parseFloat((prev + returned).toFixed(2)));
    setPositions(prev => prev.filter(p => p.id !== pos.id));
    setHistory(prev => [{
      id:         pos.id,
      sym:        pos.sym,
      type:       pos.type,
      entryPrice: pos.entryPrice,
      closePrice: price,
      pnl,
      leverage:   pos.leverage,
      closeTime:  new Date().toLocaleTimeString('tr-TR'),
    }, ...prev.slice(0, 19)]);
  };

  // Tüm pozisyonları kapat
  const closeAll = () => {
    positions.forEach(pos => closePosition(pos));
  };

  // Hesabı sıfırla
  const resetAccount = () => {
    setBalance(INITIAL_BALANCE);
    setPositions([]);
    setHistory([]);
    setTotalPnl(0);
  };

  const totalEquity = parseFloat((balance + positions.reduce((acc, pos) => {
    const diff = pos.type === 'LONG'
      ? (price - pos.entryPrice) / pos.entryPrice
      : (pos.entryPrice - price) / pos.entryPrice;
    return acc + pos.margin + pos.margin * pos.leverage * diff;
  }, 0)).toFixed(2));

  const totalReturn = parseFloat(((totalEquity - INITIAL_BALANCE) / INITIAL_BALANCE * 100).toFixed(2));

  return (
    <div className={styles.panel}>
      {/* Başlık */}
      <div className={styles.header}>
        <div className={styles.title}>🎮 Demo Hesap — Vadeli İşlem</div>
        <button className={styles.resetBtn} onClick={resetAccount}>Sıfırla</button>
      </div>

      {/* Bakiye kartları */}
      <div className={styles.balanceGrid}>
        <div className={styles.balCard}>
          <div className={styles.balLabel}>Bakiye</div>
          <div className={styles.balValue}>${balance.toLocaleString('tr-TR', { minimumFractionDigits: 2 })}</div>
        </div>
        <div className={styles.balCard}>
          <div className={styles.balLabel}>Toplam Varlık</div>
          <div className={styles.balValue} style={{ color: totalEquity >= INITIAL_BALANCE ? 'var(--accent)' : 'var(--red)' }}>
            ${totalEquity.toLocaleString('tr-TR', { minimumFractionDigits: 2 })}
          </div>
        </div>
        <div className={styles.balCard}>
          <div className={styles.balLabel}>Toplam Getiri</div>
          <div className={styles.balValue} style={{ color: totalReturn >= 0 ? 'var(--accent)' : 'var(--red)' }}>
            {totalReturn >= 0 ? '+' : ''}{totalReturn}%
          </div>
        </div>
        <div className={styles.balCard}>
          <div className={styles.balLabel}>Açık PnL</div>
          <div className={styles.balValue} style={{ color: totalPnl >= 0 ? 'var(--accent)' : 'var(--red)' }}>
            {totalPnl >= 0 ? '+' : ''}${totalPnl}
          </div>
        </div>
      </div>

      {/* İşlem formu */}
      <div className={styles.tradeForm}>
        <div className={styles.formRow}>
          <div className={styles.formGroup}>
            <label className={styles.formLabel}>Coin</label>
            <div className={styles.coinBadge}>{selectedCoin?.sym}/USDT</div>
          </div>
          <div className={styles.formGroup}>
            <label className={styles.formLabel}>Fiyat</label>
            <div className={styles.coinBadge}>{formatPrice(price)}</div>
          </div>
        </div>

        {/* Kaldıraç */}
        <div className={styles.formGroup}>
          <label className={styles.formLabel}>Kaldıraç: <span style={{ color: 'var(--accent)' }}>{leverage}x</span></label>
          <div className={styles.leverageBtns}>
            {LEVERAGE_OPTIONS.map(l => (
              <button
                key={l}
                className={`${styles.leverageBtn} ${leverage === l ? styles.active : ''}`}
                onClick={() => setLeverage(l)}
              >
                {l}x
              </button>
            ))}
          </div>
        </div>

        {/* Miktar */}
        <div className={styles.formGroup}>
          <label className={styles.formLabel}>
            Margin ($)
            <span className={styles.maxBtn} onClick={() => setAmount(Math.floor(balance / 4).toString())}>
              MAX/4
            </span>
          </label>
          <input
            className={styles.amountInput}
            type="number"
            value={amount}
            onChange={e => setAmount(e.target.value)}
            placeholder="Miktar girin..."
            min="1"
            max={balance}
          />
          <div className={styles.sizeInfo}>
            İşlem büyüklüğü: <span>${(parseFloat(amount || 0) * leverage).toFixed(2)}</span>
          </div>
        </div>

        {/* Sinyal önerisi */}
        {signal && signal.type !== 'BEKLE' && (
          <div className={`${styles.signalHint} ${signal.cls === 'buy' ? styles.hintBuy : styles.hintSell}`}>
            {signal.icon} Bot Önerisi: <b>{signal.type === 'AL' || signal.type === 'ZAYIF AL' ? 'LONG aç' : 'SHORT aç'}</b>
          </div>
        )}

        {/* Al/Sat butonları */}
        <div className={styles.tradeBtns}>
          <button
            className={styles.longBtn}
            onClick={() => openPosition('LONG')}
            disabled={!price || parseFloat(amount) > balance || parseFloat(amount) <= 0}
          >
            🚀 LONG AL
            <span>Yükseliş Bekliyorum</span>
          </button>
          <button
            className={styles.shortBtn}
            onClick={() => openPosition('SHORT')}
            disabled={!price || parseFloat(amount) > balance || parseFloat(amount) <= 0}
          >
            🔻 SHORT SAT
            <span>Düşüş Bekliyorum</span>
          </button>
        </div>
      </div>

      {/* Sekmeler */}
      <div className={styles.tabs}>
        <button
          className={`${styles.tab} ${activeTab === 'positions' ? styles.activeTab : ''}`}
          onClick={() => setActiveTab('positions')}
        >
          Açık Pozisyonlar ({positions.length})
        </button>
        <button
          className={`${styles.tab} ${activeTab === 'history' ? styles.activeTab : ''}`}
          onClick={() => setActiveTab('history')}
        >
          İşlem Geçmişi ({history.length})
        </button>
      </div>

      {/* Pozisyonlar */}
      {activeTab === 'positions' && (
        <div className={styles.positionsList}>
          {positions.length === 0 ? (
            <div className={styles.empty}>Açık pozisyon yok</div>
          ) : (
            <>
              {positions.map(pos => {
                const diff = pos.type === 'LONG'
                  ? (price - pos.entryPrice) / pos.entryPrice
                  : (pos.entryPrice - price) / pos.entryPrice;
                const pnl     = parseFloat((pos.margin * pos.leverage * diff).toFixed(2));
                const pnlPct  = parseFloat((diff * pos.leverage * 100).toFixed(2));
                const isProfit = pnl >= 0;

                return (
                  <div key={pos.id} className={styles.posCard}>
                    <div className={styles.posTop}>
                      <div className={styles.posLeft}>
                        <span className={`${styles.posBadge} ${pos.type === 'LONG' ? styles.longBadge : styles.shortBadge}`}>
                          {pos.type}
                        </span>
                        <span className={styles.posSym}>{pos.sym}/USDT</span>
                        <span className={styles.posLev}>{pos.leverage}x</span>
                      </div>
                      <button className={styles.closeBtn} onClick={() => closePosition(pos)}>
                        Kapat
                      </button>
                    </div>
                    <div className={styles.posDetails}>
                      <div className={styles.posDetail}>
                        <span>Giriş</span>
                        <span>{formatPrice(pos.entryPrice)}</span>
                      </div>
                      <div className={styles.posDetail}>
                        <span>Şu an</span>
                        <span>{formatPrice(price)}</span>
                      </div>
                      <div className={styles.posDetail}>
                        <span>Margin</span>
                        <span>${pos.margin}</span>
                      </div>
                      <div className={styles.posDetail}>
                        <span>Likidasyon</span>
                        <span style={{ color: 'var(--red)' }}>{formatPrice(pos.liquidPrice)}</span>
                      </div>
                    </div>
                    <div className={styles.posPnl} style={{ color: isProfit ? 'var(--accent)' : 'var(--red)' }}>
                      {isProfit ? '+' : ''}${pnl} ({isProfit ? '+' : ''}{pnlPct}%)
                    </div>
                  </div>
                );
              })}
              <button className={styles.closeAllBtn} onClick={closeAll}>
                Tümünü Kapat
              </button>
            </>
          )}
        </div>
      )}

      {/* Geçmiş */}
      {activeTab === 'history' && (
        <div className={styles.historyList}>
          {history.length === 0 ? (
            <div className={styles.empty}>İşlem geçmişi yok</div>
          ) : (
            history.map(h => (
              <div key={h.id} className={styles.histCard}>
                <div className={styles.histLeft}>
                  <span className={`${styles.posBadge} ${h.type === 'LONG' ? styles.longBadge : styles.shortBadge}`}>
                    {h.type}
                  </span>
                  <span className={styles.posSym}>{h.sym}</span>
                  <span className={styles.posLev}>{h.leverage}x</span>
                </div>
                <div className={styles.histMid}>
                  <span>{formatPrice(h.entryPrice)}</span>
                  <span style={{ color: 'var(--muted)' }}>→</span>
                  <span>{formatPrice(h.closePrice)}</span>
                </div>
                <div style={{ color: h.pnl >= 0 ? 'var(--accent)' : 'var(--red)', fontFamily: 'Space Mono', fontSize: '12px', fontWeight: 700 }}>
                  {h.pnl >= 0 ? '+' : ''}${h.pnl}
                </div>
              </div>
            ))
          )}
        </div>
      )}
    </div>
  );
}
